DROP TABLE IF EXISTS `profiles`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `profiles` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned NOT NULL,
  `bio` text COLLATE utf8mb4_unicode_ci,
  `subjects` json DEFAULT NULL,
  `hourly_rate` decimal(10,2) DEFAULT NULL,
  `is_available` tinyint(1) NOT NULL DEFAULT '0',
  `average_rating` decimal(3,2) NOT NULL DEFAULT '0.00',
  `total_reviews` int unsigned NOT NULL DEFAULT '0',
  `total_sessions_hosted` int unsigned NOT NULL DEFAULT '0',
  `total_sessions_attended` int unsigned NOT NULL DEFAULT '0',
  `id_verified` tinyint(1) NOT NULL DEFAULT '0',
  `phone_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `timezone` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Africa/Johannesburg',
  `language_preference` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'en',
  `teaching_specializations` json DEFAULT NULL,
  `education_level` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `years_of_experience` int unsigned DEFAULT NULL,
  `tutor_tier_id` bigint unsigned DEFAULT NULL,
  `tier_assigned_at` timestamp NULL DEFAULT NULL,
  `kyc_status` enum('not_submitted','pending','approved','rejected') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'not_submitted',
  `kyc_application_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `profiles_user_id_unique` (`user_id`),
  KEY `profiles_tutor_tier_id_foreign` (`tutor_tier_id`),
  KEY `profiles_kyc_application_id_foreign` (`kyc_application_id`),
  CONSTRAINT `profiles_kyc_application_id_foreign` FOREIGN KEY (`kyc_application_id`) REFERENCES `kyc_applications` (`id`) ON DELETE SET NULL,
  CONSTRAINT `profiles_tutor_tier_id_foreign` FOREIGN KEY (`tutor_tier_id`) REFERENCES `tutor_tiers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `profiles_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=135 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
